import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack, Grid } from '@mui/material';
import { BarChart } from '@mui/x-charts';
import response from './response.json';

interface PipelineStage {
  stage: string;
  candidates: number;
}

interface OpenPosition {
  title: string;
  location: string;
  openings: number;
}

interface HiringData {
  pipelineStages: PipelineStage[];
  timeToHire: {
    averageDays: number;
    shortestDays: number;
    longestDays: number;
  };
  openPositions: OpenPosition[];
}

export default function Widget() {
  const hiringData = response.data as HiringData;
  const { pipelineStages, timeToHire, openPositions } = hiringData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 450, bgcolor: '#1A1A1A' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Typography variant="h6" sx={{ color: '#0D47A1' }}>
            Recruitment Tracker
          </Typography>

          <Box>
            <Typography variant="body2" sx={{ color: '#FFFFFF' }}>
              Time to Hire
            </Typography>
            <Typography variant="body1" sx={{ color: '#FF5722', fontWeight: 500 }}>
              Average: {timeToHire.averageDays} days
            </Typography>
            <Stack direction="row" spacing={1} sx={{ mt: 0.5 }}>
              <Typography variant="caption" sx={{ color: '#B0BEC5' }}>
                Shortest: {timeToHire.shortestDays} days
              </Typography>
              <Typography variant="caption" sx={{ color: '#B0BEC5' }}>
                Longest: {timeToHire.longestDays} days
              </Typography>
            </Stack>
          </Box>

          <BarChart
            height={140}
            series={[{ data: pipelineStages.map(stage => stage.candidates), color: '#FF5722' }]}
            xAxis={[{
              data: pipelineStages.map(stage => stage.stage),
              scaleType: 'band',
              tickLabelStyle: { fontSize: 10, fill: '#B0BEC5' },
            }]}
            margin={{ top: 10, bottom: 30, left: 40, right: 10 }}
            sx={{ '& .MuiBarElement-root': { rx: 4 } }}
          />

          <Grid container spacing={1}>
            {openPositions.map((position, index) => (
              <Grid item xs={6} key={index}>
                <Box sx={{ bgcolor: '#2A2A2A', p: 1, borderRadius: 1 }}>
                  <Typography variant="body2" sx={{ color: '#FFFFFF' }}>
                    {position.title}
                  </Typography>
                  <Typography variant="caption" sx={{ color: '#B0BEC5' }}>
                    {position.location}
                  </Typography>
                  <Typography variant="caption" sx={{ color: '#FF5722' }}>
                    Openings: {position.openings}
                  </Typography>
                </Box>
              </Grid>
            ))}
          </Grid>
        </Stack>
      </CardContent>
    </Card>
  );
}
